// AGGREGATE and EXTEND aren't reserved words elsewhere, and AS is normally
// just used for aliasing, so these only become clause keywords in pipe position.
// See: https://cloud.google.com/bigquery/docs/reference/standard-sql/pipe-syntax
function promotePipeClauseKeywords(tokens: Token[]): Token[] {
  let prevToken = EOF_TOKEN;
  return tokens.map(token => {
    const afterPipe = prevToken.type === TokenType.PIPE;
    prevToken = token;
    if (!afterPipe) {
      return token;
    }
    const text = token.text.toUpperCase();
    if (text === 'AGGREGATE') {
      return { ...token, type: TokenType.AGGREGATE, text };
    } else if (text === 'EXTEND' || text === 'AS') {
      return { ...token, type: TokenType.RESERVED_CLAUSE, text };
    } else {
      return token;
    }
  });
